{"command":"$tools = @('cc-pdf','cc-html','cc-word','cc-excel','cc-powerpoint','cc-gmail','cc-outlook','cc-sessions','cc-whoami','cc-send','cc-ask','cc-spawn','cc-fleet-selftest','cc-vault','cc-comm-queue','cc-settings','cc-cron','cc-docgen','cc-hardware','cc-personresearch','cc-posthog','cc-director-setup','cc-playwright','cc-browser','cc-crawl4ai','cc-websiteaudit','cc-brandingrecommendations','cc-reddit','cc-spotify','cc-twitter','cc-facebook','cc-youtube','cc-image','cc-photos','cc-video','cc-voice','cc-whisper','cc-transcribe','cc-youtube-info','cc-click','cc-computer','cc-trisight');
$reg = Get-Content -Raw -LiteralPath 'D:\ReposFred\devthrottle\tools\registry.json' | ConvertFrom-Json;
$bin = Join-Path $env:LOCALAPPDATA 'cc-director\bin';
foreach ($t in $tools) {
  $entry = $reg.tools | Where-Object { $_.name -eq $t } | Select-Object -First 1;
  $src = if ($entry.source_dir) { $entry.source_dir } else { $t };
  $dir = Join-Path 'D:\ReposFred\devthrottle\tools' $src;
  $shim = Join-Path $bin ($t + '.cmd');
  $files = @();
  if (Test-Path -LiteralPath $dir) { $files = Get-ChildItem -LiteralPath $dir -File -Recurse -Depth 2 | Select-Object -ExpandProperty FullName }
  $entrypoints = @($files | Where-Object { $_ -match '\\(main\.py|pyproject\.toml|package\.json|Program\.cs|.*\.csproj|cli\.(py|mjs))$' } | ForEach-Object { $_.Substring($dir.Length + 1) });
  $readme = Test-Path -LiteralPath (Join-Path $dir 'README.md');
  $doc = Test-Path -LiteralPath ('D:\ReposFred\devthrottle\docs\tools\' + $t + '.md');
  $ship = if ($null -ne $entry.ship) { [bool]$entry.ship } else { $false };
  [pscustomobject]@{ tool=$t; ship=$ship; type=$entry.type; source=$src; sourceExists=(Test-Path -LiteralPath $dir); shim=(Test-Path -LiteralPath $shim); readme=$readme; doc=$doc; entrypoints=($entrypoints -join ', ') } | ConvertTo-Json -Compress
}","workdir":"D:\ReposFred\devthrottle","timeout_ms":20000}

